const body=$input.item.json.body||{};
const action=(body.action||'').toLowerCase();
const apiKey=$env.ANTHROPIC_API_KEY;
if(!apiKey)return[{json:{error:'ANTHROPIC_API_KEY env var not set in n8n'}}];

const claudeReq=async(systemPrompt,userMsg,maxTokens)=>{
  const payload={model:'claude-haiku-4-5-20251001',max_tokens:maxTokens||1024,messages:[{role:'user',content:userMsg}]};
  if(systemPrompt)payload.system=systemPrompt;
  const r=await fetch('https://api.anthropic.com/v1/messages',{
    method:'POST',
    headers:{'x-api-key':apiKey,'anthropic-version':'2023-06-01','content-type':'application/json'},
    body:JSON.stringify(payload)
  });
  const d=await r.json();
  return(d.content?.[0]?.text||'').trim();
};

let result;

if(action==='chat'){
  const message=(body.message||'').trim();
  if(!message)return[{json:{error:'Empty message'}}];
  const ctx=body.context||{};
  const systemPrompt=`You are Ephermal AI — an expert Meta advertising assistant built into the Ephermal platform for Shopify brands.\n\nUser's current account stats:\n- ROAS: ${ctx.roas||'unknown'}\n- Total Spend: ${ctx.spend||'unknown'}\n- Creatives Made: ${ctx.creatives||'unknown'}\n- Conversions: ${ctx.conversions||'unknown'}\n- Store: ${ctx.store_url||'not analysed'}\n\nYou help with: improving ROAS, writing UGC scripts, Meta audience targeting, budget allocation, creative performance analysis, and Meta Ads strategy. Be concise, actionable, and specific. Speak like a senior performance marketer.`;
  const reply=await claudeReq(systemPrompt,message,1024);
  result={reply:reply||'Sorry, I could not generate a response.'};

}else if(action==='describe'){
  const storeUrl=body.store_url||(body.context||{}).store_url||'';
  const prompt=`Write a compelling UGC ad product description for a Meta Ads video. The store is${storeUrl?': '+storeUrl:' a Shopify brand'}. Write 2-3 punchy sentences that a UGC creator would naturally say on camera. Focus on the main benefit, a pain point it solves, and a subtle CTA. Keep it under 100 words. Return ONLY the description, no preamble.`;
  const description=await claudeReq(null,prompt,256);
  result={description};

}else if(action==='analyze'){
  const url=(body.url||'').trim();
  if(!url||!url.startsWith('http'))return[{json:{error:'Invalid URL'}}];
  let html='';
  try{
    const pageRes=await fetch(url,{headers:{'User-Agent':'Mozilla/5.0 (compatible; Ephermal/1.0)'}});
    html=await pageRes.text();
  }catch(e){}
  const text=html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi,'')
    .replace(/<[^>]+>/g,' ')
    .replace(/\s+/g,' ')
    .trim()
    .slice(0,3000);
  const prompt=`Analyse this e-commerce store and return a JSON object with exactly these keys:\n{\n  "summary": "1-2 sentence brand/product summary",\n  "target_audience": "1-2 sentence description of ideal customer",\n  "products": ["product1", "product2", "product3"],\n  "ad_opportunities": "2-3 specific Meta ad angles that would work well",\n  "meta_strategy": "Recommended Meta Ads strategy: campaign objective, audience targeting approach, and creative angle"\n}\n\nStore URL: ${url}\nStore page content (truncated):\n${text}\n\nReturn ONLY valid JSON, no markdown, no explanation.`;
  const raw=await claudeReq(null,prompt,1024);
  let parsed={};
  try{parsed=JSON.parse(raw);}catch(e){const m=raw.match(/\{[\s\S]*\}/);try{parsed=JSON.parse(m?.[0]||'{}');}catch(e2){}}
  result={
    summary:parsed.summary||'Could not analyse store.',
    target_audience:parsed.target_audience||'—',
    products:Array.isArray(parsed.products)?parsed.products:[],
    ad_opportunities:parsed.ad_opportunities||'—',
    meta_strategy:parsed.meta_strategy||'—'
  };

}else{
  result={error:`Unknown action: ${action}`};
}

return[{json:result}];
